function normalizeText(str) {
  if (!str) return "";
  return str
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase();
}

function normalizeEmployee(str) {
  if (!str) return "";
  return str.toString().trim();
}

function parseBirthDate(input) {
  if (!input) return { raw: "", digits: "" };
  // Trim and accept either AA-MM-DD or YYYY-MM-DD
  const s = input.trim();
  // If format is YYYY-MM-DD, take last 2 digits of year
  const reShort = /^\d{2}-\d{2}-\d{2}$/;
  const reLong = /^\d{4}-\d{2}-\d{2}$/;
  if (reShort.test(s)) {
    return { raw: s, digits: s.replace(/-/g, "") }; // "89-06-01" -> "890601"
  } else if (reLong.test(s)) {
    const yy = s.slice(2, 4); // "1989-06-01" -> "89"
    return { raw: s, digits: yy + s.slice(5, 7) + s.slice(8, 10) };
  } else {
    // formato inválido: devolver vacío para que webhook lo valide / rechace
    return { raw: s, digits: "" };
  }
}

